jQuery(document).ready(function($){const prefix=WZSettingsAdmin.prefix||'wz';$('.file-browser').on('click',function(event){event.preventDefault();var self=$(this);var file_frame=wp.media.frames.file_frame=wp.media({title:self.data('uploader_title'),button:{text:self.data('uploader_button_text'),},multiple:!1});file_frame.on('select',function(){attachment=file_frame.state().get('selection').first().toJSON();self.prev('.file-url').val(attachment.url).change()});file_frame.open()});$(function(){$("#post-body-content").tabs({create:function(event,ui){$(ui.tab.find("a")).addClass("nav-tab-active")},activate:function(event,ui){$(ui.oldTab.find("a")).removeClass("nav-tab-active");$(ui.newTab.find("a")).addClass("nav-tab-active")}})});$('.color-field').each(function(i,element){$(element).wpColorPicker()});$('.reset-default-thumb').on('click',function(){var settingsKey=WZSettingsAdmin.settings_key||'';var thumbDefault=(typeof window[WZSettingsAdmin.prefix+'_admin']!=='undefined')?window[WZSettingsAdmin.prefix+'_admin'].thumb_default:'';$('#'+settingsKey+'\\[thumb_default\\]').val(thumbDefault)});$('#'+prefix+'-settings-form').on('submit',function(){formmodified=0})})